external_knowledge:
- A "top-rated coffee product" refers to a product with a high average rating, with the exact threshold for what constitutes "top-rated" dependent on the context; 
- A "most active reviewer" is a reviewer who has submitted the most reviews for a particular coffee product; 
- The ranking of reviewers is based on the number of reviews they have submitted for each coffee product, with the reviewer having the highest number of reviews ranked as 1.

sql:
SELECT image_url 
FROM coffees 
WHERE rating > (SELECT AVG(rating) FROM coffees);

SELECT name
FROM coffees
WHERE coffee_id = 0;

SELECT name
FROM coffees
WHERE rating = (SELECT MAX(rating) FROM coffees);

SELECT name, origin, rating AS average_rating, stock_quantity, image_url
FROM coffees
ORDER BY average_rating DESC;

SELECT name, rating 
FROM coffees 
ORDER BY rating DESC;
